/*
  Llama Farm Agritourism Design System
  - Colors, typography, and layout tuned to match the provided design.
*/

:root {
  /* Brand palette */
  --color-primary-brown: #7B4B2A;
  --color-primary-green: #3F7F4C;
  --color-accent-red: #C62828;

  --color-neutral-100: #FFFFFF;
  --color-neutral-150: #F8F8F8;
  --color-neutral-300: #E5E5E5;
  --color-neutral-800: #333333;

  --color-success: #3F7F4C;
  --color-error: #C62828;
  --color-warning: #F9A825;
  --color-info: #1565C0;

  --color-border-subtle: #E5E5E5;

  /* Typography */
  --font-heading: 'DM Sans', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;
  --font-code: 'Source Code Pro', monospace;

  --font-size-h1: 36px;
  --font-size-h2: 28px;
  --font-size-h3: 22px;
  --font-size-body: 16px;
  --font-size-small: 14px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale (base unit 8px) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Layout */
  --max-width: 1200px;
  --header-height: 96px;
  --border-radius-small: 4px;
  --transition-fast: 150ms ease-out;
}

/* Global reset & base styles */
* {
  box-sizing: border-box;
}

html {
  font-size: 100%;
  scroll-behavior: smooth;
}

body {
  margin: 0;
  padding: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-800);
  background-color: var(--color-neutral-100);
}

a {
  color: var(--color-primary-green);
  text-decoration: none;
}

a:hover,
a:focus-visible {
  color: var(--color-accent-red);
}

img {
  max-width: 100%;
  display: block;
}

/* Visually hidden utility */
.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  border: 0;
}

/* Skip link */
.skip-link {
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
  top: -40px;
  background-color: var(--color-accent-red);
  color: var(--color-neutral-100);
  padding: var(--space-2) var(--space-3);
  border-radius: var(--border-radius-small);
  font-weight: var(--font-weight-medium);
  z-index: 1000;
}

.skip-link:focus {
  top: var(--space-2);
}

/* Header */
.site-header {
  background-color: var(--color-neutral-100);
  border-bottom: 1px solid var(--color-border-subtle);
}

.header-inner {
  max-width: var(--max-width);
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--space-3) var(--space-3);
}

@media (min-width: 1024px) {
  .header-inner {
    padding: var(--space-3) 0;
  }
}

/* Logo approximating the traditional script + mark from the design */
.site-logo,
.footer-logo {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  text-decoration: none;
  color: var(--color-neutral-800);
}

.logo-mark {
  width: 52px;
  height: 52px;
  border-radius: 50%;
  border: 2px solid var(--color-primary-brown);
  position: relative;
}

/* Simple abstract "llama" silhouette using CSS only */
.logo-mark::before,
.logo-mark::after {
  content: '';
  position: absolute;
  background-color: var(--color-primary-brown);
}

.logo-mark::before {
  width: 18px;
  height: 26px;
  border-radius: 10px 10px 4px 4px;
  bottom: 8px;
  left: 50%;
  transform: translateX(-50%);
}

.logo-mark::after {
  width: 14px;
  height: 10px;
  border-radius: 7px 7px 3px 3px;
  bottom: 28px;
  left: 50%;
  transform: translateX(-50%);
}

.logo-text {
  display: flex;
  flex-direction: column;
  line-height: 1.1;
}

.logo-line-primary {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  font-size: 1.25rem;
}

.logo-line-secondary {
  font-size: 0.8rem;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--color-primary-brown);
}

/* Primary navigation, matching icon-over-label layout from design */
.primary-nav {
  font-family: var(--font-heading);
}

.primary-nav-list {
  list-style: none;
  display: flex;
  align-items: flex-end;
  gap: var(--space-4);
  margin: 0;
  padding: 0;
}

.primary-nav-item {
  flex: 0 0 auto;
}

.nav-link {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: var(--space-1);
  color: var(--color-primary-brown);
  font-size: 0.9rem;
  font-weight: var(--font-weight-medium);
  text-decoration: none;
  padding: var(--space-1) 0;
  transition: color var(--transition-fast);
}

.nav-link .nav-text {
  white-space: nowrap;
}

.nav-icon {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  border: 2px solid currentColor;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.95rem;
}

.nav-link:is(:hover, :focus-visible) {
  color: var(--color-primary-green);
}

.nav-link.is-active {
  color: var(--color-accent-red);
}

/* Responsive navigation adjustments */
@media (max-width: 991px) {
  .header-inner {
    flex-wrap: wrap;
    row-gap: var(--space-2);
  }

  .primary-nav {
    width: 100%;
  }

  .primary-nav-list {
    justify-content: center;
    gap: var(--space-3);
    overflow-x: auto;
    padding-bottom: var(--space-1);
  }

  .nav-link .nav-text {
    font-size: 0.8rem;
  }
}

@media (max-width: 640px) {
  .logo-text {
    display: none;
  }

  .header-inner {
    justify-content: space-between;
  }
}

/* Main content area */
.site-main {
  min-height: calc(100vh - var(--header-height));
  padding: var(--space-5) var(--space-3) var(--space-6);
}

@media (min-width: 1024px) {
  .site-main {
    padding: var(--space-6) 0 var(--space-7);
  }
}

/* Hero pattern (for use on individual pages, matches provided design) */
.hero {
  max-width: 100%;
  margin: 0 auto;
  display: grid;
  grid-template-columns: minmax(0, 1.1fr) minmax(0, 1fr);
  min-height: 420px;
}

.hero-media {
  position: relative;
  overflow: hidden;
}

.hero-media img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.hero-panel {
  position: relative;
  background: linear-gradient(to right, rgba(255, 255, 255, 0.86), rgba(255, 255, 255, 0.96));
  display: flex;
  align-items: center;
  justify-content: center;
}

.hero-panel-inner {
  max-width: 480px;
  padding: var(--space-5);
}

.hero-title {
  font-family: var(--font-heading);
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
  color: var(--color-primary-green);
  margin: 0 0 var(--space-3);
}

.hero-body {
  font-size: 1rem;
  color: var(--color-primary-brown);
  margin: 0 0 var(--space-4);
}

.hero-cta {
  display: inline-block;
  padding: 12px 28px;
  border-radius: var(--border-radius-small);
  background-color: var(--color-accent-red);
  color: var(--color-neutral-100);
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  font-size: 0.95rem;
  text-decoration: none;
}

.hero-cta:hover,
.hero-cta:focus-visible {
  background-color: #a52020;
}

@media (max-width: 900px) {
  .hero {
    grid-template-columns: 1fr;
  }

  .hero-panel-inner {
    padding: var(--space-4);
  }
}

/* Footer */
.site-footer {
  border-top: 1px solid var(--color-border-subtle);
  background-color: var(--color-neutral-150);
  padding: var(--space-5) var(--space-3) var(--space-4);
  font-size: 0.9rem;
}

.footer-inner {
  max-width: var(--max-width);
  margin: 0 auto;
  display: grid;
  grid-template-columns: minmax(0, 2.2fr) repeat(3, minmax(0, 1fr));
  gap: var(--space-5);
}

.footer-brand {
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
}

.footer-logo {
  margin-bottom: var(--space-2);
}

.footer-description {
  margin: 0;
  color: #555555;
  max-width: 360px;
}

.footer-copy {
  margin: 0;
  color: #777777;
  font-size: 0.8rem;
}

.footer-column {
  min-width: 0;
}

.footer-heading {
  font-family: var(--font-heading);
  font-size: 1rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-primary-brown);
  margin: 0 0 var(--space-2);
}

.footer-link-list {
  list-style: none;
  margin: 0;
  padding: 0;
}

.footer-link-list li + li {
  margin-top: 4px;
}

.footer-link {
  color: #555555;
  text-decoration: none;
}

.footer-link:hover,
.footer-link:focus-visible {
  color: var(--color-accent-red);
}

@media (max-width: 991px) {
  .footer-inner {
    grid-template-columns: 1fr 1fr;
    row-gap: var(--space-4);
  }

  .footer-brand {
    grid-column: 1 / -1;
  }
}

@media (max-width: 640px) {
  .footer-inner {
    grid-template-columns: 1fr;
  }

  .footer-brand {
    order: 4;
  }
}

/* Basic form styling pattern to match flat, rounded inputs from design */
.form-group {
  margin-bottom: var(--space-3);
}

.form-group label {
  display: block;
  margin-bottom: 4px;
  font-weight: var(--font-weight-medium);
}

.form-control,
textarea.form-control,
select.form-control {
  width: 100%;
  padding: 10px 12px;
  border-radius: var(--border-radius-small);
  border: 1px solid var(--color-border-subtle);
  font-family: var(--font-body);
  font-size: 0.95rem;
}

.form-control:focus,
textarea.form-control:focus,
select.form-control:focus {
  outline: none;
  border-color: var(--color-primary-green);
  box-shadow: 0 0 0 1px rgba(63, 127, 76, 0.1);
}

.form-error {
  margin-top: 4px;
  font-size: var(--font-size-small);
  color: var(--color-error);
}

/* Generic button pattern using design's red primary CTA */
.btn-primary {
  display: inline-block;
  border: none;
  border-radius: var(--border-radius-small);
  background-color: var(--color-accent-red);
  color: var(--color-neutral-100);
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  font-size: 0.95rem;
  padding: 12px 28px;
  cursor: pointer;
  text-decoration: none;
}

.btn-primary:hover,
.btn-primary:focus-visible {
  background-color: #a52020;
}
